def inspect_policy(self, flow, state, context, tools):
    if not flow.slots['source'].check_if_filled():
        self.ambiguity.declare('partial', metadata={'missing_entity': 'post'})
        return DisplayFrame(flow.name())

    slots = flow.slot_values_dict()
    post_id, _ = self._resolve_source_ids(flow, state, tools)
    params = {'post_id': post_id}
    if 'aspect' in slots:
        params['aspect'] = slots['aspect']
    if 'threshold' in slots:
        params['threshold'] = slots['threshold']

    result = tools('inspect_post', params)
    if not result['_success']:
        return self.error_frame(flow, 'tool_error',
            thoughts='inspect_post failed.',
            failed_tool='inspect_post')

    self.memory.write_scratchpad('inspect', {
        'version': 1,
        'turn_number': context.turn_id,
        'used_count': 0,
        'metrics': result.get('metrics', {}),
        'per_section': result.get('per_section', []),
        'aspect': slots.get('aspect'),
        'threshold': slots.get('threshold'),
    })

    metrics = result.get('metrics', {})
    headline = f"{metrics.get('word_count', 0)} words across {metrics.get('num_sections', 0)} sections, about {metrics.get('time_to_read', 0)} minutes to read."
    flow.status = 'Completed'
    frame = DisplayFrame(flow.name(), thoughts=headline, metadata={
        'post_id': post_id,
        'aspect': slots.get('aspect'),
        'metric_count': len(metrics),
    })
    frame.add_block({'type': 'report', 'data': {
        'post_id': post_id,
        'metrics': metrics,
        'per_section': result.get('per_section', []),
    }})
    return frame

class InspectFlow(ResearchParentFlow):
  def __init__(self):
    super().__init__()
    self.flow_type = 'inspect'
    self.dax = '{1BD}'
    self.goal = 'report numeric content metrics; word count, section count, reading time, image count, post size (MB); optionally filtered to a single metric. Use check for post metadata'
    self.slots = {
      'source': SourceSlot(1),
      'aspect': CategorySlot(['word_count', 'num_sections', 'time_to_read', 'image_count', 'num_links', 'post_size'], priority='required'),
      'threshold': ScoreSlot(priority='optional'),
    }
    # Deterministic flow — the policy calls inspect_post directly; no skill delegation.
    self.tools = ['inspect_post']
